1	import { supabase } from './supabase.js';
2	import { writeCounterfactuals } from './ips-engine.js';
3	import { upsertSequence, closeSequence } from './sequence-tracker.js';
4	import { backpropagateReward } from './reward-backprop.js';
5	import { invalidateCache } from './scoring.js';
6	import { predictDrift } from './predictive-drift.js';
7	import type { SupabaseClient } from '@supabase/supabase-js';
8	
9	type TrustLifecycleStatus = 'trusted' | 'probation' | 'sandbox' | 'suspended' | 'new';
10	const PROTECTED_TRUST_STATUSES: readonly TrustLifecycleStatus[] = ['sandbox', 'suspended'];
11	
12	function isProtectedTrustStatus(status: string | null | undefined): status is TrustLifecycleStatus {
13	    return typeof status === 'string' && PROTECTED_TRUST_STATUSES.includes(status as TrustLifecycleStatus);
14	}
15	
16	function shouldPreserveProtectedStatus(
17	    currentStatus: string | null | undefined,
18	    nextStatus: string,
19	): boolean {
20	    // Suspended is sticky until explicit manual reinstatement.
21	    if (currentStatus === 'suspended') {
22	        return nextStatus !== 'suspended';
23	    }
24	
25	    // Sandbox can escalate to suspended automatically, but cannot auto-upgrade
26	    // back into probation/trusted without an explicit operator action.
27	    if (currentStatus === 'sandbox') {
28	        return nextStatus === 'probation' || nextStatus === 'trusted' || nextStatus === 'new';
29	    }
30	
31	    return false;
32	}
