81	// ── Orchestrator Main Entrypoint ──
82	export async function orchestrateOutcome(params: OrchestratorParams): Promise<void> {
83	
84	    async function taskTrustUpdate() {
85	        // IMPORT GUARD: imported historical rows must never update agent trust.
86	        // Trust reflects live SDK signal only. skipTrust is set by the import route.
87	        if (params.skipTrust === true) return;
88	        await updateAgentTrust(params.agentId, params.customerId, params.finalSuccess,
89	            params.actionName, params.signalConfidence ?? null);
90	    }
91	
92	    async function taskContextDrift() {
93	        await detectContextDrift(supabase, params.customerId, params.issueType, params.agentId);
94	    }
95	
96	    async function taskSilentFailure() {
97	        await detectSilentFailure(supabase, {
98	            outcome_id: params.outcomeId,
99	            customer_id: params.customerId,
100	            agent_id: params.agentId,
101	            action_id: params.actionId,
102	            action_name: params.actionName,
103	            success: params.finalSuccess,
104	            outcome_score: params.finalOutcomeScore,
105	            business_outcome: params.businessOutcome ?? null,
106	            error_code: params.errorCode ?? null,
107	        });
108	    }
109	
110	    async function taskCounterfactuals() {
111	        if (params.decisionRecord?.ranked_actions) {
112	            const outcomeScore = params.finalOutcomeScore ?? (params.finalSuccess ? 1.0 : 0.0);
113	            await writeCounterfactuals({
114	                decisionId: params.decisionId!,
115	                realOutcomeId: params.outcomeId,
116	                realOutcomeScore: outcomeScore,
117	                chosenActionName: params.actionName,
118	                rankedActions: params.decisionRecord.ranked_actions,
119	                contextHash: params.decisionRecord.context_hash ?? '',
120	                episodePosition: params.decisionRecord.episode_position ?? 0,
121	            });
122	        }
123	    }
124	
125	    async function taskSequence() {
126	        if (params.episodeId) {
127	            await upsertSequence({
128	                episodeId: params.episodeId,
129	                agentId: params.agentId,
130	                customerId: params.customerId,
131	                contextHash: params.decisionRecord?.context_hash ?? `${params.contextId}:${params.issueType}`,
132	                actionName: params.actionName,
133	                responseMs: params.responseMs ?? undefined,
134	            });
135	
136	            if (params.businessOutcome === 'resolved' || params.businessOutcome === 'failed') {
137	                const finalScore = params.finalOutcomeScore ?? (params.finalSuccess ? 1.0 : 0.0);
138	                await closeSequence({
139	                    episodeId: params.episodeId,
140	                    agentId: params.agentId,
141	                    customerId: params.customerId,
142	                    finalOutcome: finalScore,
143	                });
144	
145	                await backpropagateReward({
146	                    episode_id: params.episodeId,
147	                    customer_id: params.customerId,
148	                    final_outcome: finalScore,
149	                    gamma: 0.85,
150	                });
151	            }
152	        }
153	    }
154	
155	    async function taskLatencySpike(): Promise<void> {
156	        const { data: recentOutcomes } = await supabase
157	            .from('fact_outcomes')
158	            .select('response_time_ms')
159	            .eq('agent_id', params.agentId)
160	            .eq('action_id', params.actionId)
161	            .order('timestamp', { ascending: false })
162	            .limit(20);
163	
164	        if (!recentOutcomes || recentOutcomes.length < 5) return;
165	
166	        const current = recentOutcomes[0].response_time_ms;
167	        if (!current || current <= 0) return;
168	
169	        const baselineValues = recentOutcomes
170	            .slice(1, 16)
171	            .map((r) => r.response_time_ms)
172	            .filter((v): v is number => typeof v === 'number' && v > 0)
173	            .sort((a, b) => a - b);
174	
175	        if (baselineValues.length < 3) return;
176	
177	        const mid = Math.floor(baselineValues.length / 2);
178	        const median = baselineValues[mid]!;
179	
180	        // 3× multiplier + 1000ms absolute floor prevents false positives
181	        // (e.g. an action that normally takes 50ms spiking to 200ms is not worth alerting on)
182	        if (current <= median * 3 || current <= 1000) return;
183	
184	        // Deduplicate: skip if a latency_spike alert already exists for
185	        // this (customer_id, action_id) in the last hour
186	        const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000).toISOString();
187	        const { data: existing } = await supabase
188	            .from('degradation_alert_events')
189	            .select('id')
190	            .eq('customer_id', params.customerId)
191	            .eq('action_id', params.actionId)
192	            .eq('alert_type', 'latency_spike')
193	            .gte('created_at', oneHourAgo)
194	            .limit(1);
195	
196	        if (existing && existing.length > 0) return;
197	
198	        await supabase.from('degradation_alert_events').insert({
199	            customer_id: params.customerId,
200	            agent_id: params.agentId,
201	            action_id: params.actionId,
202	            alert_type: 'latency_spike',
203	            severity: 'warning',
204	            message:
205	                `Latency spike detected on action "${params.actionName}". ` +
206	                `Current response time: ${current}ms vs median baseline: ${median}ms ` +
207	                `(${(current / median).toFixed(1)}× normal).`,
208	        });
209	    }
210	
211	    async function taskCacheInvalidation() {
212	        // Invalidate only this customer/context score cache entry so the next
213	        // getScores() call reads fresh data instead of serving a stale 5-min TTL entry.
214	        invalidateCache(params.customerId, params.contextId);
215	    }
216	
217	    async function taskPredictiveDrift(): Promise<void> {
218	        // Predictive drift only runs for live SDK outcomes, not imports.
219	        if (params.skipTrust === true) return;
220	        await predictDrift(
221	            params.actionId,
222	            params.customerId,
223	            params.agentId,
224	            params.actionName,
225	        );
226	    }
227	
228	    // Trust atomicity is guaranteed by the update_trust_and_audit() RPC (migration 062),
229	    // which writes both the trust score UPDATE and audit INSERT in one DB transaction.
230	    // Surfacing trust failures as HTTP 500 to agents is counterproductive — a trust DB
231	    // issue should not block outcome logging entirely. Run all tasks via allSettled.
232	    const results = await Promise.allSettled([
233	        taskTrustUpdate(),
234	        taskContextDrift(),
235	        taskSilentFailure(),
236	        taskCounterfactuals(),
237	        taskSequence(),
238	        taskLatencySpike(),
239	        taskCacheInvalidation(),
240	        taskPredictiveDrift(),
241	    ]);
242	
243	    const taskNames = [
244	        'trust-update',
245	        'context-drift',
246	        'silent-failure',
247	        'counterfactuals',
248	        'sequence',
249	        'latency-spike',
250	        'cache-invalidation',
251	        'predictive-drift',
252	    ];
253	
254	    const criticalTaskFailures: string[] = [];
255	
256	    results.forEach((result, index) => {
257	        if (result.status === 'rejected') {
258	            const taskName = taskNames[index];
259	            const errorMessage = (result.reason as Error)?.message ?? String(result.reason);
260	
261	            console.error(`[orchestrator:${taskName}] failed`, {
262	                error: errorMessage,
263	                outcomeId: params.outcomeId,
264	                agentId: params.agentId,
265	            });
266	
267	            if (taskName === 'trust-update' || taskName === 'counterfactuals') {
268	                criticalTaskFailures.push(
269	                    `${taskName} failed for outcome_id=${params.outcomeId} agent_id=${params.agentId}: ${errorMessage}`
270	                );
271	            }
272	        }
273	    });
274	
275	    if (criticalTaskFailures.length > 0) {
276	        void Promise.resolve(supabase.from('degradation_alert_events').insert({
277	            customer_id: params.customerId,
278	            agent_id: params.agentId,
279	            alert_type: 'orchestrator_failure',
280	            severity: 'critical',
281	            message: criticalTaskFailures.join(' | '),
282	        })).catch(() => { });
283	    }
284	
285	    // Non-blocking: refresh trust cache row for dashboard reads.
286	    // Trust score/status authority is updateAgentTrust() via update_trust_and_audit RPC.
287	    // IMPORT GUARD: skip for imported rows — trust reflects SDK signal only.
288	    if (params.skipTrust !== true) {
289	        refreshLiveTrustCache(params.agentId).catch((err) =>
290	            console.warn('[orchestrator] refreshLiveTrustCache failed:', (err as Error).message)
291	        );
292	    }
293	}
