295	// ══════════════════════════════════════════════════════════════
296	// Webhook Callback Handler — Layer 2/3 Score Overwrite
297	// ══════════════════════════════════════════════════════════════
298	//
299	// 3-Layer Outcome Score Model:
300	//   Layer 1 (technical): Initial score from gateway inference
301	//   Layer 2 (session):    Webhook callback overwrites score
302	//   Layer 3 (business):   Webhook callback overwrites again
303	//
304	// Append-only log (webhook_callback_log) preserves full timeline —
305	// all three writes are recorded immutably. The latest write per layer
306	// is authoritative for scoring.
307	//
308	// Idempotency: duplicate (decision_id, layer) → returns existing result.
309	// ══════════════════════════════════════════════════════════════
310	
311	export async function handleWebhookCallback(
312	  params: WebhookCallbackParams,
313	): Promise<WebhookCallbackResult> {
314	  // ── 1. Idempotency check ──────────────────────────────────
315	  const { data: existingLog } = await supabase
316	    .from('webhook_callback_log')
317	    .select('outcome_id, previous_score, new_score')
318	    .eq('decision_id', params.decisionId)
319	    .eq('layer', params.layer)
320	    .order('received_at', { ascending: false })
321	    .limit(1)
322	    .maybeSingle();
323	
324	  if (existingLog) {
325	    return {
326	      resolved: true,
327	      outcomeId: existingLog.outcome_id,
328	      idempotent: true,
329	      layer: params.layer,
330	      previousScore: existingLog.previous_score,
331	      newScore: existingLog.new_score,
332	    };
333	  }
334	
335	  // ── 2. Resolve decision_id → outcome ──────────────────────
336	  const { data: outcome } = await supabase
337	    .from('fact_outcomes')
338	    .select('outcome_id, customer_id, outcome_score, success')
339	    .eq('decision_id', params.decisionId)
340	    .order('timestamp', { ascending: false })
341	    .limit(1)
342	    .maybeSingle();
343	
344	  if (!outcome) {
345	    return {
346	      resolved: false,
347	      outcomeId: null,
348	      idempotent: false,
349	      layer: params.layer,
350	      previousScore: null,
351	      newScore: params.score,
352	    };
353	  }
354	
355	  const previousScore = typeof outcome.outcome_score === 'number'
356	    ? outcome.outcome_score
357	    : null;
358	  const newScore = clamp01Score(params.score);
359	
360	  // ── 3. Update fact_outcomes with new score ─────────────────
361	  const nowIso = new Date().toISOString();
362	  const updateData: Record<string, unknown> = {
363	    outcome_score: newScore,
364	    feedback_received_at: nowIso,
365	    signal_updated_at: nowIso,
366	  };
367	
368	  // Layer 3 (business) also updates business_outcome
369	  if (params.layer === 3) {
370	    updateData.business_outcome = params.success ? 'resolved' : 'failed';
371	  }
372	
373	  const { error: updateError } = await supabase
374	    .from('fact_outcomes')
375	    .update(updateData)
376	    .eq('outcome_id', outcome.outcome_id)
377	    .eq('customer_id', outcome.customer_id);
378	
379	  if (updateError) {
380	    console.error('[orchestrator:webhook-callback] outcome update failed:', updateError.message);
381	    throw new Error(`Failed to update outcome ${outcome.outcome_id}: ${updateError.message}`);
382	  }
383	
384	  // ── 4. Write append-only log ──────────────────────────────
385	  const logEntry = {
386	    decision_id: params.decisionId,
387	    outcome_id: outcome.outcome_id,
388	    customer_id: outcome.customer_id,
389	    layer: params.layer,
390	    success: params.success,
391	    previous_score: previousScore,
392	    new_score: newScore,
393	    reason: params.reason ?? null,
394	    metadata: params.metadata ?? null,
395	    webhook_timestamp: params.timestamp,
396	    received_at: nowIso,
397	  };
398	
399	  const { error: logError } = await supabase
400	    .from('webhook_callback_log')
401	    .insert(logEntry);
402	
403	  if (logError) {
404	    // Log write is best-effort — score update already committed.
405	    // Duplicate key on (decision_id, layer) is handled by idempotency check above.
406	    console.warn('[orchestrator:webhook-callback] append-log write failed:', logError.message);
407	  }
408	
409	  // ── 5. Invalidate caches ──────────────────────────────────
410	  invalidateCache(outcome.customer_id, params.decisionId);
411	
412	  return {
413	    resolved: true,
414	    outcomeId: outcome.outcome_id,
415	    idempotent: false,
416	    layer: params.layer,
417	    previousScore,
418	    newScore,
419	  };
420	}
421	
422	function clamp01Score(value: number): number {
423	  if (!Number.isFinite(value)) return 0.5;
424	  if (value < 0) return 0;
425	  if (value > 1) return 1;
426	  return value;
427	}
428	
429	// ── Live Trust Cache Refresh (fire-and-forget) ──
430	// Read-only for existing rows: never recomputes trust score/status.
431	// Bootstrap-only write: inserts a neutral row if the trigger-minted row is missing.
432	async function refreshLiveTrustCache(
433	    agentId: string,
434	): Promise<void> {
435	    const { data: trustRow, error } = await supabase
436	        .from('agent_trust_scores')
437	        .select('agent_id, trust_score, trust_status, total_decisions, consecutive_failures')
438	        .eq('agent_id', agentId)
439	        .maybeSingle();
440	
441	    if (error) {
442	        console.warn('[trust] refreshLiveTrustCache: failed to read agent_trust_scores:', error.message);
443	        return;
444	    }
445	
446	    if (trustRow) {
447	        return;
448	    }
449	
450	    const { error: bootstrapError } = await supabase
451	        .from('agent_trust_scores')
452	        .upsert({
453	            agent_id: agentId,
454	            trust_score: null,
455	            trust_status: 'new',
456	            consecutive_failures: 0,
457	            total_decisions: 0,
458	            updated_at: new Date().toISOString(),
459	        }, { onConflict: 'agent_id' });
460	
461	    if (bootstrapError) {
462	        console.warn(
463	            '[trust] refreshLiveTrustCache: failed to bootstrap missing trust row:',
464	            bootstrapError.message,
465	        );
466	    }
467	}
468	
469	// ── Trust Snapshot (fire-and-forget) ──────────────────────────
470	async function snapshotTrust(
471	    agentId: string,
472	    trust: { trust_score: number; trust_status: string; consecutive_failures: number },
473	    reason: 'pre_failure' | 'pre_incident' | 'manual',
474	    incidentId?: string,
475	): Promise<void> {
476	    await supabase.from('agent_trust_snapshots').insert({
477	        agent_id: agentId,
478	        trust_score: trust.trust_score,
479	        trust_status: trust.trust_status,
480	        consecutive_failures: trust.consecutive_failures,
481	        snapshot_reason: reason,
482	        incident_id: incidentId ?? null,
483	    });
484	}
485	
486	/**
487	 * Updates agent trust score using exponential smoothing.
488	 *
489	 * Formula:
490	 *   On success: new_score = min(score × 1.03, 1.0)
491	 *               consecutive_failures reset to 0
492	 *   On failure: new_score = score × (0.9 ^ consecutive_failures)
493	 *               consecutive_failures incremented
494	 *
495	 * Status thresholds:
496	 *   score >= 0.6                       → trusted
497	 *   score 0.3–0.6                      → probation
498	 *   score 0.1–0.3 OR failures >= 5     → sandbox
499	 *   score < 0.1  OR failures >= 10     → suspended
500	 *
501	 * Cold-start prior: 0.70 (set on first DB insert by account-setup trigger).
502	 * First real outcome moves score to ~0.721 (success) or ~0.567 (failure).
503	 *
504	 * Note: scoring.ts uses a separate Bayesian (Laplace) smoothing formula for
505	 * composite action scores (computeCompositeScore). These are independent calculations.
506	 * This function uses exponential smoothing only.
507	 */
508	async function updateAgentTrust(
509	    agentId: string,
510	    customerId: string,
511	    success: boolean,
512	    actionName?: string,
513	    signalConfidence?: number | null,
514	): Promise<void> {
515	    const { data: trust } = await supabase
516	        .from('agent_trust_scores')
517	        .select('trust_id, trust_score, total_decisions, correct_decisions, consecutive_failures, trust_status, suspension_reason')
518	        .eq('agent_id', agentId)
519	        .maybeSingle();
520	
521	    if (!trust) {
522	        // The fn_init_agent_trust() trigger (migration 058) should
523	        // have created this row. If it's missing, throw so the
524	        // orchestrator's allSettled logs a [trust-update] error.
525	        // Do NOT silently return - a missing row is a data integrity issue.
526	        throw new Error(
527	            `[trust] No agent_trust_scores row for agent_id=${agentId}. ` +
528	            `Trigger fn_init_agent_trust may have failed at agent creation.`
529	        );
530	    }
531	
532	    const currentScore = typeof trust.trust_score === 'number' ? trust.trust_score : 0.7;
533	    const currentTotalDecisions = typeof trust.total_decisions === 'number' ? trust.total_decisions : 0;
534	    const currentCorrectDecisions = typeof trust.correct_decisions === 'number' ? trust.correct_decisions : 0;
535	    const currentFailures = typeof trust.consecutive_failures === 'number' ? trust.consecutive_failures : 0;
536	    const currentStatus = typeof trust.trust_status === 'string' ? trust.trust_status : 'trusted';
537	    const currentSuspensionReason = typeof trust.suspension_reason === 'string' ? trust.suspension_reason : null;
538	
539	    // Always capture old values before any mutation.
540	    // These are written to every audit row so the dashboard can show
541	    // the score delta for each event in the Trust History timeline.
542	    const oldScore = currentScore;
543	    const oldStatus = currentStatus;
544	
545	    let newScore: number;
546	    let newFailures: number;
547	    let newCorrect = currentCorrectDecisions;
548	
549	    if (success) {
550	        newFailures = 0;
551	        newCorrect += 1;
552	        // ── Phase 1: Signal confidence weighting ──────────────
553	        // High-confidence signals (e.g. Stripe webhooks, explicit SDK)
554	        // contribute the full 3% growth. Low-confidence signals (e.g.
555	        // LLM evaluation at 0.3) contribute proportionally less.
556	        // When signalConfidence is null/1.0 → 1 + 0.03*1.0 = 1.03 (unchanged).
557	        const confidence = signalConfidence ?? 1.0;
558	        newScore = Math.min(currentScore * (1 + 0.03 * confidence), 1.0);
559	    } else {
560	        // ── Coordinated Failure Interlock ──────────────────────
561	        // Check if this failure is infrastructure-attributed before
562	        // applying decay. detect_coordinated_failures() looks for 3+
563	        // agents failing the same action within the last 5 minutes.
564	        let isInfrastructureFailure = false;
565	        if (actionName) {
566	            try {
567	                const { data: coordFailures, error: coordError } = await supabase.rpc('detect_coordinated_failures', {
568	                    window_minutes: 5,
569	                    min_agent_count: 3,
570	                });
571	                if (coordError) throw new Error(coordError.message);
572	                if (coordFailures && Array.isArray(coordFailures)) {
573	                    isInfrastructureFailure = coordFailures.some(
574	                        (row: { action_name: string }) => row.action_name === actionName
575	                    );
576	                }
577	            } catch (err) {
578	                // Coordination check failed — proceed with normal decay (fail safe)
579	                console.warn('[trust] Coordinated failure check failed:', (err as Error).message);
580	            }
581	        }
582	
583	        if (isInfrastructureFailure) {
584	            snapshotTrust(agentId, trust, 'pre_incident', `coordinated:${actionName ?? 'unknown'}`).catch(() => { });
585	
586	            const { error: auditError } = await supabase.from('agent_trust_audit').insert({
587	                agent_id: agentId,
588	                customer_id: customerId,
589	                event_type: 'failure_excluded_infrastructure',
590	                old_score: oldScore,
591	                new_score: oldScore,        // score unchanged — frozen
592	                old_status: oldStatus,
593	                new_status: oldStatus,      // status unchanged — frozen
594	                reason: `Failure excluded: coordinated infrastructure failure detected on action "${actionName}". Trust score frozen.`,
595	            });
596	            if (auditError) {
597	                throw new Error(`[trust] failed to write audit event: ${auditError.message}`);
598	            }
599	
600	            await supabase.from('degradation_alert_events').insert({
601	                customer_id: customerId,
602	                agent_id: agentId,
603	                alert_type: 'coordinated_failure',
604	                severity: 'critical',
605	                message:
606	                    `Coordinated infrastructure failure detected on action "${actionName}". ` +
607	                    `3+ agents failed this action within 5 minutes. ` +
608	                    `Trust score frozen for affected agents.`,
609	            });
610	
611	            console.info('[trust] Failure excluded — coordinated infrastructure event', { agentId, actionName });
612	            return; // No trust modification
613	        }
614	
615	        // Normal agent-attributable failure: snapshot then decay
616	        snapshotTrust(agentId, trust, 'pre_failure').catch(() => { });
617	        newFailures = currentFailures + 1;
618	        newScore = currentScore * Math.pow(0.9, newFailures);
619	    }
620	
621	    let newStatus: string;
622	    let newSuspensionReason: string | null = null;
623	
624	    if (newScore < 0.1 || newFailures >= 10) {
625	        newStatus = 'suspended';
626	        newSuspensionReason = newScore < 0.1 ? 'trust_score_critically_low' : 'consecutive_failures_exceeded';
627	    } else if (newScore < 0.3 || newFailures >= 5) {
628	        newStatus = 'sandbox';
629	        newSuspensionReason = newFailures >= 5 ? 'consecutive_failures_exceeded' : null;
630	    } else if (newScore < 0.6) {
631	        newStatus = 'probation';
632	    } else {
633	        newStatus = 'trusted';
634	    }
635	
636	    if (shouldPreserveProtectedStatus(currentStatus, newStatus)) {
637	        console.warn(
638	            '[trust] updateAgentTrust: preserving protected status to avoid flip-flop',
639	            { agentId, currentStatus, computedStatus: newStatus }
640	        );
641	
642	        newStatus = currentStatus as TrustLifecycleStatus;
643	        if (newStatus === 'suspended') {
644	            newSuspensionReason = currentSuspensionReason ?? 'manual_reinstatement_required';
645	        } else if (newStatus === 'sandbox') {
646	            newSuspensionReason = currentSuspensionReason;
647	        }
648	    }
649	
650	    // ── ML-CHECK-2.1-B FIX: atomic trust UPDATE + audit INSERT via RPC ──
651	    // Previously: two separate supabase calls. If the audit INSERT failed,
652	    // trust score was already updated with no audit record (INVARIANT 7 violation).
653	    // Now: both ops execute inside one PL/pgSQL transaction (migration 052).
654	    // Either both succeed or both are rolled back.
655	    //
656	    // Reason format is intentional — agent.tsx parseActionFromReason()
657	    // relies on exactly these two patterns to extract the action name:
658	    //   "Outcome success via SDK: {actionName}"
659	    //   "Outcome failure recorded: {actionName}"
660	    // Status-change events append a transition note that
661	    // parseStatusLabel() in agent.tsx picks up separately.
662	
663	    const action = actionName?.trim() || 'unknown_action';
664	    const statusChanged = oldStatus !== newStatus;
665	
666	    const baseReason = success
667	        ? `Outcome success via SDK: ${action}`
668	        : `Outcome failure recorded: ${action}`;
669	
670	    const reason = statusChanged
671	        ? `${baseReason} | Trust recalibrated: ${oldStatus} → ${newStatus}`
672	        : baseReason;
673	
674	    const { error: rpcError } = await supabase.rpc('update_trust_and_audit', {
675	        p_agent_id: agentId,
676	        p_customer_id: customerId,
677	        p_trust_score: newScore,
678	        p_total_decisions: currentTotalDecisions + 1,
679	        p_correct_decisions: newCorrect,
680	        p_consecutive_failures: newFailures,
681	        p_trust_status: newStatus,
682	        p_suspension_reason: newSuspensionReason,
683	        p_updated_at: new Date().toISOString(),
684	        p_event_type: success ? 'success' : 'failure',
685	        p_old_score: oldScore,
686	        p_old_status: oldStatus,
687	        p_new_status: newStatus,
688	        p_performed_by: 'outcome-orchestrator',
689	        p_reason: reason,
690	    });
691	
692	    if (rpcError) {
693	        throw new Error(`[trust] atomic trust+audit update failed: ${rpcError.message}`);
694	    }
695	}
