697	// ── FIX: detectContextDrift — scope by customer_id ────────────
698	// BEFORE: context lookup used only issue_type with no customer_id filter.
699	// This meant Customer A's contexts were matched against Customer B's
700	// outcomes, causing false "context drift" alerts across customers.
701	//
702	// AFTER: every query is scoped by customer_id. Each customer only
703	// sees their own contexts and their own outcomes.
704	async function detectContextDrift(
705	    sb: SupabaseClient,
706	    customerId: string,
707	    contextType: string,
708	    agentId: string,
709	): Promise<void> {
710	    const { data: existingContext } = await sb
711	        .from('dim_contexts')
712	        .select('context_id')
713	        .eq('customer_id', customerId)       // FIX: was missing — caused cross-customer matches
714	        .eq('issue_type', contextType)
715	        .limit(1)
716	        .maybeSingle();
717	
718	    if (existingContext) {
719	        const { count } = await sb
720	            .from('fact_outcomes')
721	            .select('outcome_id', { count: 'exact', head: true })
722	            .eq('customer_id', customerId)
723	            .eq('context_id', existingContext.context_id);
724	
725	        if ((count ?? 0) > 0) return;
726	    }
727	
728	    const { data: recentAlert } = await sb
729	        .from('degradation_alert_events')
730	        .select('alert_id')
731	        // TODO: Add (customer_id, alert_type, context_type) composite unique constraint
732	        // to degradation_alert_events once a context_type column is added (migration TBD).
733	        // Until then, message-based ilike dedup is the deduplication mechanism.
734	        .eq('customer_id', customerId)
735	        .eq('alert_type', 'context_drift')
736	        .gte('detected_at', new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString())
737	        .ilike('message', `%"${contextType}"%`)
738	        .limit(1);
739	
740	    if (recentAlert && recentAlert.length > 0) return;
741	
742	    await sb.from('degradation_alert_events').insert({
743	        customer_id: customerId,
744	        alert_type: 'context_drift',
745	        severity: 'warning',
746	        message: `New context type "${contextType}" encountered by agent ${agentId}. No prior outcomes for this customer. Cold-start protocol activated.`,
747	    });
748	}
