254	export function computeOutcomeDataQuality(params: {
255	    outcomeScoreRaw: number | null | undefined;
256	    isInconsistent: boolean;
257	    mappingConfidence: number;
258	    businessOutcome: string | null | undefined;
259	    inferenceConfidence?: number | null;
260	}): number {
261	    let score = 1.0;
262	
263	    if (params.outcomeScoreRaw === null || params.outcomeScoreRaw === undefined) {
264	        // Score was inferred — penalize by inverse of inference confidence.
265	        // High confidence inference (0.75) → penalty ~0.06
266	        // Low confidence inference (0.30)  → penalty ~0.18
267	        // No inference at all              → penalty 0.25 (original behavior)
268	        const conf = params.inferenceConfidence ?? 0;
269	        const penalty = conf > 0
270	            ? Math.max(0.05, 0.25 * (1 - conf))
271	            : 0.25;
272	        score -= penalty;
273	    }
274	
275	    if (params.isInconsistent) score -= 0.20;
276	    if (params.mappingConfidence < 0.70) score -= 0.20;
277	    if (!params.businessOutcome) score -= 0.10;
278	    
279	    return Number(Math.max(0.0, score).toFixed(4));
280	}
