284	    outcomeScoreRaw: number | null;
285	    businessOutcome: string | null | undefined;
286	}): InconsistencyEvaluation {
287	    const lowThreshold = clamp01(
288	        Number(process.env.LI_INCONSISTENCY_THRESHOLD ?? 0.3)
289	    );
290	    const highThreshold = clamp01(
291	        Number(process.env.LI_INCONSISTENCY_HIGH_THRESHOLD ?? 0.7)
292	    );
