579	async function findNearDuplicateOutcome(params: {
580	    customerId: string;
581	    agentId: string;
582	    actionId: string;
583	    contextId: string;
584	    taskName: string;
585	    success: boolean;
586	    sourceEventAt: Date;
587	    dedupWindowMs: number;
588	    outcomeScoreRaw: number | null;
589	    responseTimeMs: number | null;
590	    errorCode: string | null;
591	    businessOutcome: string | null;
592	}): Promise<string | null> {
593	    const start = new Date(params.sourceEventAt.getTime() - params.dedupWindowMs).toISOString();
594	    const end = new Date(params.sourceEventAt.getTime() + params.dedupWindowMs).toISOString();
595	
596	    const { data, error } = await supabase
597	        .from('fact_outcomes')
598	        .select('outcome_id, outcome_score_raw, response_time_ms, error_code, business_outcome')
599	        .eq('customer_id', params.customerId)
600	        .eq('agent_id', params.agentId)
601	        .eq('action_id', params.actionId)
602	        .eq('context_id', params.contextId)
603	        .eq('task_name', params.taskName)
604	        .eq('success', params.success)
605	        .eq('is_deleted', false)
606	        .eq('is_synthetic', false)
607	        .eq('ingestion_source', 'import')
608	        .gte('timestamp', start)
609	        .lte('timestamp', end)
610	        .order('timestamp', { ascending: false })
611	        .limit(5);
612	
613	    if (error) {
614	        console.warn('[ingest-core] near-duplicate lookup failed:', error.message);
615	        return null;
616	    }
617	
618	    for (const row of (data ?? []) as Array<Record<string, unknown>>) {
619	        const candidateOutcomeId = typeof row.outcome_id === 'string' ? row.outcome_id : null;
620	        if (!candidateOutcomeId) continue;
621	
622	        const matches = isNearDuplicateCandidate(
623	            {
624	                outcome_score_raw: typeof row.outcome_score_raw === 'number' ? row.outcome_score_raw : null,
625	                response_time_ms: typeof row.response_time_ms === 'number' ? row.response_time_ms : null,
626	                error_code: typeof row.error_code === 'string' ? row.error_code : null,
627	                business_outcome: typeof row.business_outcome === 'string' ? row.business_outcome : null,
628	            },
629	            {
630	                outcomeScoreRaw: params.outcomeScoreRaw,
631	                responseTimeMs: params.responseTimeMs,
632	                errorCode: params.errorCode,
633	                businessOutcome: params.businessOutcome,
634	            },
635	        );
636	
637	        if (matches) {
638	            return candidateOutcomeId;
639	        }
640	    }
641	
642	    return null;
643	}
