701	
702	/**
703	 * Insert a single normalized outcome row into fact_outcomes.
704	 * All callers (SDK route + import route) go through this function.
705	 */
706	export async function ingestOutcome(
707	    row: NormalizedOutcomeRow,
708	    customerId: string,
709	    opts: IngestCoreOptions,
710	): Promise<IngestCoreResult> {
711	    // 1. Resolve task name
712	    const taskInferResult = resolveTaskName(row.task_name, row.issue_type);
713	
714	    // Preserve parser-provided mapping metadata when available.
715	    if (
716	        typeof row.task_mapping_confidence === 'number'
717	        && Number.isFinite(row.task_mapping_confidence)
718	        && typeof row.task_mapping_tier === 'string'
719	        && isTaskMappingTier(row.task_mapping_tier)
720	    ) {
721	        taskInferResult.confidence = Math.max(0, Math.min(1, row.task_mapping_confidence));
722	        taskInferResult.tier = row.task_mapping_tier;
723	        if (row.task_name && row.task_name.trim().length > 0) {
724	            taskInferResult.task = row.task_name;
725	        }
726	    }
727	
728	    // 2. Idempotency check
729	    if (row.idempotency_key) {
730	        const existing = await checkIdempotency(row.idempotency_key, customerId);
731	        if (existing) {
732	            const replayRequestedStatus = normalizeExecutionStatus(row.execution_status ?? null);
733	            const replayExecutionStatus: ExecutionStatus = replayRequestedStatus
734	                ?? (row.success ? 'COMPLETED' : 'FAILED');
735	            const replayStatusOrigin: StatusOrigin = normalizeStatusOrigin(row.status_origin)
736	                ?? (replayRequestedStatus ? 'explicit' : 'inferred_from_success');
737	
738	            // Return existing outcome — no duplicate insert
739	            return {
740	                outcomeId: existing,
741	                actionId: '', // Not available for idempotent replays
742	                timestamp: new Date().toISOString(),
743	                ingestionQuality: {
744	                    data_quality: 1.0,
745	                    score_origin: 'provided',
746	                    is_inconsistent: false,
747	                    mapping_tier: 'idempotent_replay',
748	                    mapping_confidence: 1.0,
749	                    inference_confidence: null,
750	                    outcome_class: null,
751	                    execution_status: replayExecutionStatus,
752	                    status_origin: replayStatusOrigin,
753	                },
754	            };
755	        }
756	    }
757	
758	    // 3. Verification — reconstruct VerifierSignal from NormalizedOutcomeRow fields.
759	    // The sync path gets verifier_signal from the SDK body directly (log-outcome.ts:1203).
760	    // The queued path stores it as verifier_source/verifier_value in the NormalizedOutcomeRow.
761	    // Both paths must apply the same hallucination correction logic.
762	    const verifierSignal = row.verifier_source
763	        ? { source: row.verifier_source as any, value: row.verifier_value ?? undefined }
764	        : undefined;
765	    const verification = resolveVerifiedSuccess(row.success, row.outcome_score ?? null, verifierSignal);
766	
767	    const computedOutcomeScoreRaw: number | null =
768	        row.outcome_score !== undefined && row.outcome_score !== null
769	            ? Math.max(0, Math.min(1, row.outcome_score))
770	            : null;
771	
772	    const computedFinalSuccess = verification.verified_success;
773	    const computedFinalOutcomeScore: number | null =
774	        verification.confidence_override !== null
775	            ? verification.confidence_override
776	            : computedOutcomeScoreRaw;
777	
778	    const finalSuccess = opts.precomputed?.finalSuccess ?? computedFinalSuccess;
779	    const finalOutcomeScore = opts.precomputed?.finalOutcomeScore ?? computedFinalOutcomeScore;
780	    const outcomeScoreRaw = opts.precomputed?.outcomeScoreRaw ?? computedOutcomeScoreRaw;
781	    const scoreOrigin: 'provided' | 'inferred' =
782	        opts.precomputed?.scoreOrigin
783	        ?? (outcomeScoreRaw !== null ? 'provided' : 'inferred');
784	
785	    const requestedStatus = normalizeExecutionStatus(row.execution_status ?? null);
786	    if (requestedStatus && ((requestedStatus === 'COMPLETED') !== finalSuccess)) {
787	        throw new Error('STATUS_CONFLICT:execution_status conflicts with resolved success value');
788	    }
789	
790	    const scoreDerivedStatus = statusFromOutcomeScore(outcomeScoreRaw);
791	    if (requestedStatus && scoreDerivedStatus && requestedStatus !== scoreDerivedStatus) {
792	        throw new Error('STATUS_CONFLICT:execution_status conflicts with outcome_score_raw polarity');
793	    }
794	
795	    const executionStatus: ExecutionStatus = requestedStatus
796	        ?? (finalSuccess ? 'COMPLETED' : 'FAILED');
797	
798	    const statusOrigin: StatusOrigin = normalizeStatusOrigin(row.status_origin)
799	        ?? (requestedStatus
800	            ? 'explicit'
801	            : scoreOrigin === 'inferred'
802	                ? 'inferred_from_score'
803	                : 'inferred_from_success');
804	
805	    // 4. Inconsistency + quality
806	    const computedInconsistency = evaluateInconsistencyRules({
807	        finalSuccess,
808	        outcomeScoreRaw,
809	        businessOutcome: row.business_outcome ?? null,
810	    });
811	
812	    const inconsistency = {
813	        isInconsistent: opts.precomputed?.isInconsistent ?? computedInconsistency.isInconsistent,
814	        type: opts.precomputed?.inconsistencyType ?? computedInconsistency.type,
815	        reason: opts.precomputed?.inconsistencyReason ?? computedInconsistency.reason,
816	        ruleVersion: opts.precomputed?.inconsistencyRuleVersion ?? computedInconsistency.ruleVersion,
817	    };
818	
819	    let mappingConfidence = opts.precomputed?.mappingConfidence ?? taskInferResult.confidence;
820	    const mappingTier = opts.precomputed?.mappingTier ?? taskInferResult.tier;
821	    // dataQuality computed after inference — see step 10 below
822	
823	    // 5. FK resolution
824	    const resolvedAction = opts.resolvedActionId
825	        ? {
826	            actionId: opts.resolvedActionId,
827	            resolvedActionName: opts.resolvedActionName ?? row.action_name,
828	        }
829	        : await resolveActionIdForIngest(row.action_name, customerId);
830	
831	    const actionId = resolvedAction.actionId;
832	    const resolvedActionName = resolvedAction.resolvedActionName;
833	
834	    const contextId = opts.resolvedContextId
835	        ?? await resolveContextIdForIngest(
836	            customerId,
837	            row.issue_type,
838	            row.environment,
839	            row.customer_tier,
840	        );
841	
842	    // Best-effort context vector upkeep. Never blocks ingestion.
843	    const ensureEmbedding = contextEmbed.ensureContextEmbedding?.({
844	        contextId,
845	        customerId,
846	        issueType: row.issue_type,
847	        customerTier: row.customer_tier ?? null,
848	        environment: row.environment ?? null,
849	        rawContext: row.raw_context ?? null,
850	    });
851	    if (ensureEmbedding) {
852	        ensureEmbedding.catch((err: any) => {
853	            console.warn('[ingest-core] ensureContextEmbedding failed:', err?.message ?? err);
854	        });
855	    }
856	
857	    // 6. Semantic cluster
858	    const semanticCluster: SemanticActionClusterResult = inferSemanticActionCluster({
859	        actionName: resolvedActionName,
860	        issueType: row.issue_type,
861	        taskName: taskInferResult.task,
862	    });
863	
864	    // 7. Business outcome normalization
865	    const VALID_BUSINESS_OUTCOMES = new Set(['resolved', 'partial', 'failed', 'unknown']);
866	    const normalizedBusinessOutcome = row.business_outcome
867	        ? (VALID_BUSINESS_OUTCOMES.has(row.business_outcome) ? row.business_outcome : 'unknown')
868	        : null;
869	
870	    // 8. Session ID — import rows get a stable UUID derived from idempotency key
871	    // so replay is safe. Real SDK rows always have their own session_id.
872	    const incomingSessionId = typeof row.session_id === 'string' ? row.session_id.trim() : null;
873	    const sessionId = isUuid(incomingSessionId)
874	        ? incomingSessionId
875	        : row.idempotency_key
876	            ? deterministicUuidFromSeed(`session:${row.idempotency_key}`)
877	            : crypto.randomUUID();
878	
879	    // 9. Sanitize free-text fields
880	    const safeErrorMessage = row.error_message ? sanitizeString(row.error_message, 1000) : null;
881	    const safeErrorCode = row.error_code ? sanitizeString(row.error_code, 100) : null;
882	
883	    let failureReasonCode = normalizeFailureReasonCode(row.failure_reason_code);
884	    let failureStage = normalizeFailureStage(row.failure_stage);
885	
886	    if (executionStatus === 'COMPLETED') {
887	        failureReasonCode = null;
888	        failureStage = null;
889	    } else {
890	        if (!failureReasonCode) {
891	            failureReasonCode = normalizeFailureReasonCode(safeErrorCode) ?? 'execution_failed';
892	        }
893	        if (!failureStage) {
894	            failureStage = row.feedback_signal === 'delayed'
895	                ? 'delayed_feedback'
896	                : 'action_execution';
897	        }
898	    }
899	
900	    // 10. Outcome Score Inference — 3-layer engine
901	    // When developer omits outcome_score, infer from hard + soft + relative signals.
902	    // By default this runs for live SDK rows only.
903	    // Import rows can opt in via enableInferenceWhenSkipTrust=true.
904	    let resolvedScore = finalOutcomeScore;
905	    let resolvedScoreOrigin = scoreOrigin;
906	    let resolvedScoreConfidence: number | null = null;
907	    let resolvedOutcomeClass: string | null = null;
908	
909	    const shouldInferScore =
910	        resolvedScore === null
911	        && (!opts.skipTrustUpdate || opts.enableInferenceWhenSkipTrust === true);
912	
913	    if (shouldInferScore) {
914	        const baseline = await fetchActionBaseline(row.agent_id, actionId);
915	        const inferred = inferOutcomeScore({
916	            success: finalSuccess,
917	            retryAttempt: row.retry_attempt ?? null,
918	            responseMs: row.response_time_ms ?? null,
919	            errorCode: safeErrorCode,
920	            errorMessage: safeErrorMessage,
921	            businessOutcome: normalizedBusinessOutcome,
922	            feedbackSignal: row.feedback_signal ?? null,
923	            crossEventStatus: row.cross_event_status ?? null,
924	            verifierSource: row.verifier_source ?? null,
925	            verifierValue: row.verifier_value ?? null,
926	            actionBaseline: baseline,
927	        });
928	        resolvedScore = inferred.score;
929	        resolvedScoreOrigin = 'inferred';
930	        resolvedScoreConfidence = inferred.confidence;
931	        resolvedOutcomeClass = inferred.class;
932	    }
933	
934	    // 10a. Signal contradiction feedback — degraded/uncertain outcomes
935	    // degrade mapping confidence. The outcome score itself is already adjusted
936	    // by inference; this penalizes the TASK MAPPING quality when signals disagree.
937	    if (resolvedOutcomeClass === 'degraded' || resolvedOutcomeClass === 'uncertain') {
938	        mappingConfidence = Math.max(0, mappingConfidence - 0.05);
939	    }
940	
941	    // 10b. Data quality — computed AFTER inference so penalty reflects confidence.
942	    const dataQuality = opts.precomputed?.dataQuality ?? computeOutcomeDataQuality({
943	        outcomeScoreRaw,
944	        isInconsistent: inconsistency.isInconsistent,
945	        mappingConfidence,
946	        businessOutcome: row.business_outcome ?? null,
947	        inferenceConfidence: resolvedScoreConfidence,
948	    });
949	
950	    // Import replay safety: suppress near-duplicate writes around the same
951	    // source event timestamp when payloads are semantically equivalent.
952	    const nearDuplicateWindowMs = parseNearDedupWindowMs(opts.dedupWindowMs);
953	    if (
954	        opts.ingestionSource === 'import'
955	        && nearDuplicateWindowMs > 0
956	        && opts.sourceEventAt
957	    ) {
958	        const nearDuplicateOutcomeId = await findNearDuplicateOutcome({
959	            customerId,
960	            agentId: row.agent_id,
961	            actionId,
962	            contextId,
963	            taskName: taskInferResult.task,
964	            success: finalSuccess,
965	            sourceEventAt: opts.sourceEventAt,
966	            dedupWindowMs: nearDuplicateWindowMs,
967	            outcomeScoreRaw,
968	            responseTimeMs: row.response_time_ms ?? null,
969	            errorCode: safeErrorCode,
970	            businessOutcome: normalizedBusinessOutcome,
971	        });
972	
973	        if (nearDuplicateOutcomeId) {
974	            await saveIdempotencyRecord(row.idempotency_key, nearDuplicateOutcomeId, customerId);
975	            return {
976	                outcomeId: nearDuplicateOutcomeId,
977	                actionId,
978	                timestamp: opts.sourceEventAt.toISOString(),
979	                ingestionQuality: {
980	                    data_quality: dataQuality,
981	                    score_origin: resolvedScoreOrigin,
982	                    is_inconsistent: inconsistency.isInconsistent,
983	                    mapping_tier: 'near_duplicate_replay',
984	                    mapping_confidence: mappingConfidence,
985	                    inference_confidence: resolvedScoreConfidence,
986	                    outcome_class: resolvedOutcomeClass,
987	                    execution_status: executionStatus,
988	                    status_origin: statusOrigin,
989	                },
990	            };
991	        }
992	    }
993	
994	    // 11. timestamp — use source_event_at if provided (preserves historical ordering),
995	    // else let the DB default to now().
996	    const timestampOverride = opts.sourceEventAt
997	        ? opts.sourceEventAt.toISOString()
998	        : undefined;
999	
1000	    // 12. Insert
1001	    const insertPayload: Record<string, unknown> = {
1002	        agent_id: row.agent_id,
1003	        action_id: actionId,
1004	        context_id: contextId,
