1	/**
2	 * LLM Narrative Generator for Recommendations
3	 *
4	 * Replaces the static template strings in reason.ts with LLM-generated
5	 * context-aware explanations. Uses OpenAI gpt-4o-mini (cheap, fast).
6	 *
7	 * Graceful degradation: if the LLM call fails or the env flag is off,
8	 * the static template text is returned unchanged.
9	 *
10	 * Env vars:
11	 *   ENABLE_RECOMMENDATION_NARRATIVE=true   — gates the whole feature
12	 *   OPENAI_API_KEY                         — required when feature is on
13	 *   RECOMMENDATION_NARRATIVE_MODEL         — defaults to gpt-4o-mini
14	 */
15	
16	import type { ActionableOutput } from './reason.js';
17	
18	const ENABLED = process.env.ENABLE_RECOMMENDATION_NARRATIVE === 'true';
19	const OPENAI_API_KEY = process.env.OPENAI_API_KEY ?? '';
20	const MODEL = process.env.RECOMMENDATION_NARRATIVE_MODEL ?? 'gpt-4o-mini';
21	
22	function parsePositiveInt(raw: string | undefined, fallback: number): number {
23	    const parsed = Number.parseInt(raw ?? '', 10);
24	    if (!Number.isFinite(parsed) || parsed <= 0) return fallback;
25	    return parsed;
26	}
27	
28	const NARRATIVE_TIMEOUT_MS = parsePositiveInt(
29	    process.env.RECOMMENDATION_NARRATIVE_TIMEOUT_MS,
30	    1500,
31	);
32	const NARRATIVE_CACHE_TTL_MS = parsePositiveInt(
33	    process.env.RECOMMENDATION_NARRATIVE_CACHE_TTL_MS,
34	    60_000,
35	);
36	
37	export interface NarrativeContext {
38	    // Core recommendation fields
39	    task: string;
40	    state: string;
41	    confidence_pct: number;
42	    confidence_label: string;
43	    best_action: string | null;
44	    best_rate_pct: string | null;
45	    worst_action: string | null;
46	    worst_rate_pct: string | null;
47	    delta_pct: string | null;
48	    sample_size_best: number | null;
49	    sample_size_worst: number | null;
50	    min_sample_count: number;
51	    decision_type: 'collect_more_data' | 'monitor' | 'replace';
52	
53	    // Signal quality
54	    reliability_band: 'stable' | 'watch' | 'anomalous' | null;
55	    reliability_reasons: string[];
56	    silent_failure_warning: boolean;
57	    data_freshness_stale: boolean;
58	    data_freshness_age_hours: number | null;
59	    scope: 'agent_scoped' | 'customer_blended';
60	    scope_fallback_applied: boolean;
61	    confidence_source: string;
62	    confidence_source_reason: string;
63	
64	    // What the static templates already generated
65	    static_summary: string;
66	    static_evidence: string;
67	    static_confidence_note: string;
68	    static_message: string;
69	}
70	
71	export interface NarrativeOutput {
72	    summary: string;
73	    evidence: string;
74	    confidence_note: string;
75	    message: string;
76	    /** One-line plain-English headline for the card header */
77	    headline: string;
78	    /** 2-3 sentence narrative expanding on why one action is better */
79	    narrative: string;
80	    /** 1-3 concrete next steps the developer should take */
81	    next_steps: string[];
82	    /** 0-2 risk factors that could change this recommendation */
83	    risk_factors: string[];
84	    /** Overall trend direction based on available signal */
85	    trend_direction: 'improving' | 'stable' | 'degrading' | 'unknown';
86	}
87	
88	function buildPrompt(ctx: NarrativeContext): string {
89	    const lines: string[] = [
90	        `You are the AI engine for Layerinfinite, a decision-intelligence platform that helps developers know which action their AI agent should take for a given task.`,
91	        ``,
92	        `Generate a short, clear, developer-friendly recommendation narrative. Be direct. No marketing language. No fluff. Use concrete numbers from the data.`,
93	        ``,
94	        `## Recommendation context`,
95	        `Task name: ${ctx.task}`,
96	        `State: ${ctx.state}`,
97	        `Decision: ${decision_type_label(ctx.decision_type)}`,
98	        `Best action: ${ctx.best_action ?? 'none yet'}`,
99	        `Best success rate: ${ctx.best_rate_pct ?? 'unknown'}`,
100	        `Worst action: ${ctx.worst_action ?? 'none yet'}`,
101	        `Worst success rate: ${ctx.worst_rate_pct ?? 'unknown'}`,
102	        `Performance gap: ${ctx.delta_pct ?? 'unknown'}`,
103	        `Samples (best/worst): ${ctx.sample_size_best ?? '?'} / ${ctx.sample_size_worst ?? '?'}`,
104	        `Minimum sample count: ${ctx.min_sample_count}`,
105	        `Confidence: ${ctx.confidence_pct}% (${ctx.confidence_label})`,
106	        `Signal reliability band: ${ctx.reliability_band ?? 'unknown'}`,
107	        ctx.reliability_reasons.length > 0
108	            ? `Reliability signals: ${ctx.reliability_reasons.join('; ')}`
109	            : '',
110	        `Silent failure warning: ${ctx.silent_failure_warning ? 'YES — some outcomes marked success=true had low outcome scores' : 'no'}`,
111	        `Data freshness: ${ctx.data_freshness_stale ? `STALE (${ctx.data_freshness_age_hours?.toFixed(1) ?? '?'}h old)` : 'fresh'}`,
112	        `Data scope: ${ctx.scope === 'agent_scoped' ? 'this agent only' : ctx.scope_fallback_applied ? 'blended (agent scope not yet mature)' : 'blended across all agents'}`,
113	        `Confidence source: ${ctx.confidence_source} — ${ctx.confidence_source_reason}`,
114	        ``,
115	        `## What to generate`,
116	        `Return a JSON object with exactly these keys:`,
117	        `- "headline": 10-15 words max. The single most important thing a developer should know right now. No hedging.`,
118	        `- "summary": 1-2 sentences. Why is one action better, or why can't we say yet? Be specific.`,
119	        `- "narrative": 2-3 sentences. Expand on the analysis: what does the performance gap mean in practice, what is the trajectory, and is the signal mature enough to act on?`,
120	        `- "evidence": 1 sentence. Cite the numbers: rates, sample counts, gap size.`,
121	        `- "confidence_note": 1 sentence. Explain what drives the confidence level and what would change it.`,
122	        `- "message": 1 sentence imperative. Tell the developer exactly what to do next.`,
123	        `- "next_steps": array of 1-3 short strings. Concrete actions the developer should take now (e.g. "Promote escalate_to_human as the default action", "Continue logging outcomes for auto_retry").`,
124	        `- "risk_factors": array of 0-2 short strings. What could invalidate or reverse this recommendation (e.g. "Success rate for escalate_to_human has declined 6pp this cycle", "Data freshness is low"). Empty array if none.`,
125	        `- "trend_direction": one of "improving", "stable", "degrading", "unknown". Based on signal quality, confidence trajectory, and whether the recommendation is strengthening or weakening.`,
126	        ``,
127	        `Rules:`,
128	        `- Use the actual action names (e.g. "${ctx.best_action ?? 'action_name'}")`,
129	        `- Use percentages (e.g. "73.2%") not decimals`,
130	        `- If state is no_data or collect_more_data: focus on what to log, not performance; next_steps should be about logging`,
131	        `- If silent_failure_warning: mention that success signals may be unreliable in narrative and add it as a risk_factor`,
132	        `- If reliability is anomalous or watch: note the uncertainty in narrative`,
133	        `- If data is stale: mention that evidence is old in narrative and add it as a risk_factor`,
134	        `- If scope fallback is active: note recommendations come from the broader agent pool`,
135	        `- trend_direction should be "improving" when confidence is high and data is fresh, "degrading" when reliability is anomalous or stale, "stable" otherwise`,
136	        `- Do NOT say "Layerinfinite recommends" — write as the system speaking directly`,
137	        `- Do NOT use em-dashes`,
138	        `- Return ONLY the JSON object, no markdown fences`,
139	    ].filter((l) => l !== undefined);
140	
141	    return lines.join('\n');
142	}
143	
144	// Hack to make the prompt builder not need a method on context
145	function decision_type_label(type: NarrativeContext['decision_type']): string {
146	    if (type === 'replace') return 'Replace worst action with best action';
147	    if (type === 'monitor') return 'Monitor — do not switch yet';
148	    return 'Collect more data — no recommendation yet';
149	}
150	
151	// In-flight dedup: same context fingerprint → share one LLM promise
152	const inflightCalls = new Map<string, Promise<NarrativeOutput | null>>();
153	const responseCache = new Map<string, { value: NarrativeOutput; expiresAt: number }>();
154	
155	function contextFingerprint(ctx: NarrativeContext): string {
156	    return [
157	        ctx.task,
158	        ctx.state,
159	        ctx.confidence_pct,
160	        ctx.best_action,
161	        ctx.worst_action,
162	        ctx.delta_pct,
163	        ctx.min_sample_count,
164	        ctx.reliability_band,
165	        ctx.silent_failure_warning,
166	        ctx.scope,
167	        ctx.scope_fallback_applied,
168	    ].join('|');
169	}
170	
171	async function callOpenAI(prompt: string): Promise<NarrativeOutput | null> {
172	    if (!OPENAI_API_KEY) {
173	        console.warn('[llm-narrative] OPENAI_API_KEY not set — skipping narrative');
174	        return null;
175	    }
176	
177	    const controller = new AbortController();
178	    const timeout = setTimeout(() => controller.abort(), NARRATIVE_TIMEOUT_MS);
179	
180	    try {
181	        const res = await fetch('https://api.openai.com/v1/chat/completions', {
182	            method: 'POST',
183	            signal: controller.signal,
184	            headers: {
185	                'Content-Type': 'application/json',
186	                'Authorization': `Bearer ${OPENAI_API_KEY}`,
187	            },
188	            body: JSON.stringify({
189	                model: MODEL,
190	                temperature: 0,
191	                max_tokens: 700,
192	                messages: [
193	                    { role: 'user', content: prompt },
194	                ],
195	            }),
196	        });
197	
198	        if (!res.ok) {
199	            console.warn(`[llm-narrative] OpenAI error ${res.status}`);
200	            return null;
201	        }
202	
203	        const json = await res.json() as {
204	            choices?: Array<{ message?: { content?: string } }>;
205	        };
206	
207	        const raw = json.choices?.[0]?.message?.content?.trim() ?? '';
208	        if (!raw) return null;
209	
210	        // Strip markdown fences if the model added them anyway
211	        const cleaned = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
212	
213	        const parsed = JSON.parse(cleaned) as Partial<NarrativeOutput>;
214	
215	        // Validate required string keys are non-empty
216	        const requiredStrings: (keyof NarrativeOutput)[] = ['headline', 'summary', 'narrative', 'evidence', 'confidence_note', 'message'];
217	        for (const key of requiredStrings) {
218	            if (typeof parsed[key] !== 'string' || (parsed[key] as string).trim() === '') {
219	                console.warn(`[llm-narrative] missing key "${key}" in LLM response`);
220	                return null;
221	            }
222	        }
223	
224	        // Coerce array fields with safe fallbacks
225	        const next_steps = Array.isArray(parsed.next_steps)
226	            ? parsed.next_steps.filter((s): s is string => typeof s === 'string' && s.trim() !== '')
227	            : [];
228	        const risk_factors = Array.isArray(parsed.risk_factors)
229	            ? parsed.risk_factors.filter((s): s is string => typeof s === 'string' && s.trim() !== '')
230	            : [];
231	        const validTrendDirections = ['improving', 'stable', 'degrading', 'unknown'] as const;
232	        const trend_direction = validTrendDirections.includes(parsed.trend_direction as any)
233	            ? (parsed.trend_direction as NarrativeOutput['trend_direction'])
234	            : 'unknown';
235	
236	        return {
237	            ...(parsed as Pick<NarrativeOutput, 'headline' | 'summary' | 'narrative' | 'evidence' | 'confidence_note' | 'message'>),
238	            next_steps,
239	            risk_factors,
240	            trend_direction,
241	        };
242	    } catch (err: any) {
243	        if (err?.name !== 'AbortError') {
244	            console.warn('[llm-narrative] call failed:', err.message);
245	        }
246	        return null;
247	    } finally {
248	        clearTimeout(timeout);
249	    }
250	}
