252	/**
253	 * Generate an LLM narrative for a recommendation.
254	 *
255	 * Returns null when:
256	 * - ENABLE_RECOMMENDATION_NARRATIVE is not 'true'
257	 * - OPENAI_API_KEY is not set
258	 * - The LLM call fails or times out
259	 * - The response cannot be parsed
260	 *
261	 * The caller should fall back to static template text in all null cases.
262	 */
263	export async function generateNarrative(
264	    output: ActionableOutput,
265	    extra: {
266	        reliability_band: 'stable' | 'watch' | 'anomalous' | null;
267	        reliability_reasons: string[];
268	        silent_failure_warning: boolean;
269	        data_freshness_stale: boolean;
270	        data_freshness_age_hours: number | null;
271	        scope: 'agent_scoped' | 'customer_blended';
272	        scope_fallback_applied: boolean;
273	        confidence_source: string;
274	        confidence_source_reason: string;
275	    },
276	): Promise<NarrativeOutput | null> {
277	    if (!ENABLED) return null;
278	
279	    const ctx: NarrativeContext = {
280	        task: output.task,
281	        state: output.state,
282	        confidence_pct: output.confidence_meta.percent,
283	        confidence_label: (output.confidence_meta as any).label ?? 'none',
284	        best_action: output.insight.best_action,
285	        best_rate_pct: output.insight.best_rate !== null
286	            ? `${(output.insight.best_rate * 100).toFixed(1)}%`
287	            : null,
288	        worst_action: output.insight.worst_action,
289	        worst_rate_pct: output.insight.worst_rate !== null
290	            ? `${(output.insight.worst_rate * 100).toFixed(1)}%`
291	            : null,
292	        delta_pct: output.insight.delta !== null
293	            ? `+${(output.insight.delta * 100).toFixed(1)}%`
294	            : null,
295	        sample_size_best: output.insight.sample_size?.best ?? null,
296	        sample_size_worst: output.insight.sample_size?.worst ?? null,
297	        min_sample_count: output.progress.current_samples,
298	        decision_type: output.decision.type,
299	
300	        ...extra,
301	
302	        // Static fallbacks (so the model can use them as hints)
303	        static_summary: output.reason.summary,
304	        static_evidence: output.reason.evidence,
305	        static_confidence_note: output.reason.confidence_note,
306	        static_message: output.message,
307	    };
308	
309	    const fingerprint = contextFingerprint(ctx);
310	
311	    const cached = responseCache.get(fingerprint);
312	    if (cached && cached.expiresAt > Date.now()) {
313	        return cached.value;
314	    }
315	    if (cached && cached.expiresAt <= Date.now()) {
316	        responseCache.delete(fingerprint);
317	    }
318	
319	    const existing = inflightCalls.get(fingerprint);
320	    if (existing) return existing;
321	
322	    const prompt = buildPrompt(ctx);
323	
324	    const promise = callOpenAI(prompt)
325	        .then((output) => {
326	            if (output) {
327	                responseCache.set(fingerprint, {
328	                    value: output,
329	                    expiresAt: Date.now() + NARRATIVE_CACHE_TTL_MS,
330	                });
331	            }
332	            return output;
333	        })
334	        .finally(() => {
335	            inflightCalls.delete(fingerprint);
336	        });
337	
338	    inflightCalls.set(fingerprint, promise);
339	    return promise;
340	}
