1	export interface VerifierSignal {
2	    source: 'http_status_code' | 'database_row_count' | 'human_review' | 'downstream_webhook' | 'none';
3	    value?: number | boolean | string;
4	    verified_at?: string;
5	}
6	
7	export function resolveVerifiedSuccess(
8	    agentSuccess: boolean,
9	    outcomeScore: number | undefined | null,
10	    verifierSignal: VerifierSignal | undefined
11	): {
12	    verified_success: boolean;
13	    confidence_override: number | null;
14	    discrepancy_detected: boolean;
15	} {
16	    let verified_success = agentSuccess;
17	    let confidence_override: number | null = null;
18	
19	    if (!verifierSignal || verifierSignal.source === 'none') {
20	        return {
21	            verified_success,
22	            confidence_override,
23	            discrepancy_detected: false,
24	        };
25	    }
26	
27	    if (verifierSignal.source === 'human_review') {
28	        if (verifierSignal.value === false) {
29	            verified_success = false;
30	            confidence_override = 0.0;
31	        } else if (verifierSignal.value === true) {
32	            verified_success = true;
33	            confidence_override = 1.0;
34	        }
35	    } else if (verifierSignal.source === 'http_status_code') {
36	        const status = Number(verifierSignal.value);
37	        if (status >= 200 && status < 300) {
38	            verified_success = true;
39	        } else if (status >= 400) {
40	            verified_success = false;
41	            if (status >= 500) {
42	                confidence_override = 0.0;
43	            }
44	        }
45	    } else if (verifierSignal.source === 'database_row_count') {
46	        const rows = Number(verifierSignal.value);
47	        if (rows > 0) {
48	            verified_success = true;
49	        } else if (rows === 0) {
50	            verified_success = false;
51	            confidence_override = 0.0;
52	        }
53	    }
54	
55	    const discrepancy_detected = agentSuccess === true && verified_success === false;
56	
57	    return {
58	        verified_success,
59	        confidence_override,
60	        discrepancy_detected,
61	    };
62	}
