1	/**
2	 * LayerInfinite API — coach-session-tracker.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Session-level coaching limits for the LLM Coach.
5	 *
6	 * Rules:
7	 *   - Max 3 coaching injections per agent session
8	 *   - Sessions expire after 30 minutes of inactivity
9	 *   - Coaching retires automatically when a task_type has
10	 *     ≥ 50 outcomes (statistical scoring is sufficient)
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	interface CoachSessionState {
15	  agentId: string;
16	  sessionStart: number;
17	  coachingCount: number;
18	  /** Per-task-type outcome counts known at coaching time. */
19	  taskOutcomeCounts: Map<string, number>;
20	}
21	
22	const MAX_COACHING_PER_SESSION = 3;
23	const SESSION_TTL_MS = 30 * 60 * 1000;
24	const RETIRE_OUTCOME_THRESHOLD = 50;
25	const CLEANUP_INTERVAL_MS = 5 * 60 * 1000;
26	
27	export class CoachSessionTracker {
28	  private readonly sessions = new Map<string, CoachSessionState>();
29	  private cleanupTimer: ReturnType<typeof setInterval> | null = null;
30	
31	  /**
32	   * Check whether coaching is allowed for this agent + task_type.
33	   * Returns false if the session cap (3) is reached or if the
34	   * task_type has enough historical outcomes for statistical scoring.
35	   */
36	  canCoach(agentId: string, taskType: string, taskOutcomeCount = 0): boolean {
37	    this.cleanExpired();
38	
39	    if (taskOutcomeCount >= RETIRE_OUTCOME_THRESHOLD) return false;
40	
41	    const state = this.getOrCreate(agentId);
42	    if (state.coachingCount >= MAX_COACHING_PER_SESSION) return false;
43	
44	    return true;
45	  }
46	
47	  /**
48	   * Record a coaching injection. Returns true if recorded,
49	   * false if the cap was already reached.
50	   */
51	  recordCoaching(agentId: string, taskType: string): boolean {
52	    this.cleanExpired();
53	
54	    const state = this.getOrCreate(agentId);
55	    if (state.coachingCount >= MAX_COACHING_PER_SESSION) return false;
56	
57	    state.coachingCount++;
58	    state.taskOutcomeCounts.set(
59	      taskType,
60	      (state.taskOutcomeCounts.get(taskType) ?? 0) + 1,
61	    );
62	    return true;
63	  }
64	
65	  /**
66	   * Update the known outcome count for a task_type.
67	   * Once ≥ 50, coaching retires for that task_type permanently.
68	   */
69	  setTaskOutcomeCount(agentId: string, taskType: string, count: number): void {
70	    const state = this.getOrCreate(agentId);
71	    state.taskOutcomeCounts.set(taskType, count);
72	  }
73	
74	  /** Remaining coaching slots for this agent's current session. */
75	  remainingCoachingSlots(agentId: string): number {
76	    this.cleanExpired();
77	    const state = this.sessions.get(agentId);
78	    if (!state) return MAX_COACHING_PER_SESSION;
79	    return Math.max(0, MAX_COACHING_PER_SESSION - state.coachingCount);
80	  }
81	
82	  get activeSessionCount(): number {
83	    this.cleanExpired();
84	    return this.sessions.size;
85	  }
86	
87	  // ── Private ──────────────────────────────────────────────────
88	
89	  private getOrCreate(agentId: string): CoachSessionState {
90	    const existing = this.sessions.get(agentId);
91	    if (existing) return existing;
92	
93	    const state: CoachSessionState = {
94	      agentId,
95	      sessionStart: Date.now(),
96	      coachingCount: 0,
97	      taskOutcomeCounts: new Map(),
98	    };
99	    this.sessions.set(agentId, state);
100	
101	    if (!this.cleanupTimer) {
102	      this.cleanupTimer = setInterval(() => this.cleanExpired(), CLEANUP_INTERVAL_MS).unref();
103	    }
104	
105	    return state;
106	  }
107	
108	  private cleanExpired(): void {
109	    const cutoff = Date.now() - SESSION_TTL_MS;
110	    for (const [id, state] of this.sessions) {
111	      if (state.sessionStart < cutoff) {
112	        this.sessions.delete(id);
113	      }
114	    }
115	    if (this.sessions.size === 0 && this.cleanupTimer) {
116	      clearInterval(this.cleanupTimer);
117	      this.cleanupTimer = null;
118	    }
119	  }
120	}
