1	/**
2	 * Layerinfinite — lib/schema-inferrer.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * LLM-Powered Auto-Mapping for unknown agent trace formats.
5	 *
6	 * When a user uploads data that is NOT LangChain/LangGraph and NOT
7	 * already in Layerinfinite's standard schema, this module:
8	 *
9	 *   1. Samples the first 5 records from the uploaded data.
10	 *   2. Sends ONLY the structure (5 sample rows) to a fast LLM.
11	 *   3. Receives a deterministic mapping: { "action_name": "payload.step.command", ... }
12	 *   4. Applies that mapping to ALL rows using lodash-style deep-get.
13	 *
14	 * SAFETY RULES:
15	 *   - The LLM NEVER sees all the data — only 5 samples.
16	 *   - The LLM output is validated against a strict JSON schema.
17	 *   - If the LLM returns garbage, we reject immediately (fail-closed).
18	 *   - The mapping is applied deterministically — no LLM in the hot path.
19	 *   - Every inferred mapping is logged for audit.
20	 * ══════════════════════════════════════════════════════════════
21	 */
22	
23	// ── Types ─────────────────────────────────────────────────────
24	
25	/** The field mapping contract the LLM must produce. */
26	export interface SchemaMapping {
27	    /** JSON path to the action/tool/function name */
28	    action_name: string;
29	    /** JSON path to the issue type / task category / intent */
30	    issue_type: string | null;
31	    /** JSON path to the success/failure indicator */
32	    success: string;
33	    /** JSON path to the error message, if any */
34	    error_message: string | null;
35	    /** JSON path to the error code, if any */
36	    error_code: string | null;
37	    /** JSON path to the response time / latency in ms */
38	    response_time_ms: string | null;
39	    /** JSON path to the session / trace / request identifier */
40	    session_id: string | null;
41	    /** JSON path to the episode / thread / conversation ID */
42	    episode_id: string | null;
43	    /** JSON path to the environment (prod/staging/dev) */
44	    environment: string | null;
45	    /** JSON path to the outcome score (0-1 or 0-100) */
46	    outcome_score: string | null;
47	    /** JSON path to the business outcome / resolution status */
48	    business_outcome: string | null;
49	    /** JSON path to the timestamp of the event */
50	    timestamp: string | null;
51	    /** JSON path to the token count or resource cost */
52	    resource_cost_units: string | null;
53	    /** JSON path to the retry attempt number */
54	    retry_attempt: string | null;
