217	// ── Mapping Validation ────────────────────────────────────────
218	
219	const REQUIRED_MAPPING_FIELDS: (keyof SchemaMapping)[] = ['action_name', 'success'];
220	const ALL_MAPPING_FIELDS: (keyof SchemaMapping)[] = [
221	    'action_name', 'issue_type', 'success', 'error_message', 'error_code',
222	    'response_time_ms', 'session_id', 'episode_id', 'environment',
223	    'outcome_score', 'business_outcome', 'timestamp', 'resource_cost_units',
224	    'retry_attempt', 'task_name', 'detected_framework', 'confidence',
225	];
226	
227	/**
228	 * Validates the raw LLM output is a valid SchemaMapping.
229	 * Returns normalized mapping or null with error reason.
230	 */
231	export function validateMapping(raw: unknown): { mapping: SchemaMapping | null; error: string | null } {
232	    if (typeof raw !== 'object' || raw === null || Array.isArray(raw)) {
233	        return { mapping: null, error: 'LLM returned non-object' };
234	    }
235	
236	    const obj = raw as Record<string, unknown>;
237	
238	    // Check required fields are strings
239	    for (const field of REQUIRED_MAPPING_FIELDS) {
240	        if (typeof obj[field] !== 'string' || obj[field] === '') {
241	            return { mapping: null, error: `Required field "${field}" missing or empty in LLM mapping` };
242	        }
243	    }
244	
245	    // Build normalized mapping
246	    const mapping: SchemaMapping = {
247	        action_name: obj.action_name as string,
248	        issue_type: typeof obj.issue_type === 'string' ? obj.issue_type : null,
249	        success: obj.success as string,
250	        error_message: typeof obj.error_message === 'string' ? obj.error_message : null,
251	        error_code: typeof obj.error_code === 'string' ? obj.error_code : null,
252	        response_time_ms: typeof obj.response_time_ms === 'string' ? obj.response_time_ms : null,
253	        session_id: typeof obj.session_id === 'string' ? obj.session_id : null,
254	        episode_id: typeof obj.episode_id === 'string' ? obj.episode_id : null,
255	        environment: typeof obj.environment === 'string' ? obj.environment : null,
256	        outcome_score: typeof obj.outcome_score === 'string' ? obj.outcome_score : null,
257	        business_outcome: typeof obj.business_outcome === 'string' ? obj.business_outcome : null,
258	        timestamp: typeof obj.timestamp === 'string' ? obj.timestamp : null,
259	        resource_cost_units: typeof obj.resource_cost_units === 'string' ? obj.resource_cost_units : null,
260	        retry_attempt: typeof obj.retry_attempt === 'string' ? obj.retry_attempt : null,
261	        task_name: typeof obj.task_name === 'string' ? obj.task_name : null,
262	        detected_framework: typeof obj.detected_framework === 'string' ? obj.detected_framework : 'custom',
263	        confidence: typeof obj.confidence === 'number' && obj.confidence >= 0 && obj.confidence <= 1
264	            ? obj.confidence
265	            : 0.5,
266	    };
267	
268	    return { mapping, error: null };
269	}
270	
271	// ── Spot-Check: Validate the mapping against sample data ──────
272	
273	/**
274	 * After the LLM returns a mapping, we verify it actually extracts
275	 * valid data from the samples. If action_name or success can't be
276	 * resolved from the first 3 samples, we reject the mapping.
277	 *
278	 * This is the critical safety gate — the LLM can hallucinate paths
279	 * that don't exist. This function catches that.
280	 */
281	export function spotCheckMapping(
282	    mapping: SchemaMapping,
283	    samples: Record<string, unknown>[],
284	): { valid: boolean; error: string | null; extractionRate: number } {
285	    const checkSamples = samples.slice(0, Math.min(3, samples.length));
286	    let actionHits = 0;
287	    let successHits = 0;
288	
289	    for (const sample of checkSamples) {
290	        const actionVal = deepGet(sample, mapping.action_name);
291	        if (actionVal !== undefined && actionVal !== null && String(actionVal).trim().length > 0) {
292	            actionHits++;
293	        }
294	
295	        const successVal = deepGet(sample, mapping.success);
296	        if (successVal !== undefined && successVal !== null) {
297	            successHits++;
298	        }
299	    }
300	
301	    const actionRate = actionHits / checkSamples.length;
302	    const successRate = successHits / checkSamples.length;
303	
304	    if (actionRate < 0.67) {
305	        return {
306	            valid: false,
307	            error: `Mapping for "action_name" (path: "${mapping.action_name}") did not resolve in ${checkSamples.length - actionHits}/${checkSamples.length} samples.`,
308	            extractionRate: actionRate,
309	        };
310	    }
311	
312	    if (successRate < 0.67) {
313	        return {
314	            valid: false,
315	            error: `Mapping for "success" (path: "${mapping.success}") did not resolve in ${checkSamples.length - successHits}/${checkSamples.length} samples.`,
316	            extractionRate: successRate,
317	        };
318	    }
319	
320	    // Count how many optional fields resolved
321	    let optionalHits = 0;
322	    let optionalTotal = 0;
323	    const optionalPaths = [
324	        mapping.issue_type, mapping.error_message, mapping.response_time_ms,
325	        mapping.session_id, mapping.episode_id, mapping.timestamp,
326	    ].filter(Boolean) as string[];
327	
328	    for (const path of optionalPaths) {
329	        optionalTotal++;
330	        for (const sample of checkSamples) {
331	            const val = deepGet(sample, path);
332	            if (val !== undefined && val !== null) {
333	                optionalHits++;
334	                break; // found at least one hit for this path
335	            }
336	        }
337	    }
338	
339	    const overallRate = optionalTotal > 0
340	        ? (actionRate + successRate + (optionalHits / optionalTotal)) / 3
341	        : (actionRate + successRate) / 2;
342	
343	    return { valid: true, error: null, extractionRate: overallRate };
344	}
345	
346	// ── Apply Mapping to Records ──────────────────────────────────
347	
348	/**
349	 * Takes the LLM-inferred mapping and re-keys ALL records into
350	 * Layerinfinite's standard schema. This is the deterministic
351	 * hot-path — no LLM involved.
352	 */
353	export function applyMapping(
354	    records: Record<string, unknown>[],
355	    mapping: SchemaMapping,
356	): Record<string, unknown>[] {
357	    return records.map((record) => {
358	        const mapped: Record<string, unknown> = {};
359	
360	        // Required fields
361	        mapped.action_name = deepGet(record, mapping.action_name);
362	        mapped.success = deepGet(record, mapping.success);
363	
364	        // Optional fields — only set if path exists in mapping AND the value is
365	        // present in this record. Skipping undefined prevents downstream code
366	        // from seeing a key with an undefined value (e.g. 'session_id' in record
367	        // returning true with value undefined).
368	        const optionals: [string, string | null][] = [
369	            ['issue_type', mapping.issue_type],
370	            ['error_message', mapping.error_message],
371	            ['error_code', mapping.error_code],
372	            ['response_time_ms', mapping.response_time_ms],
373	            ['session_id', mapping.session_id],
374	            ['episode_id', mapping.episode_id],
375	            ['environment', mapping.environment],
376	            ['outcome_score', mapping.outcome_score],
377	            ['business_outcome', mapping.business_outcome],
378	            ['timestamp', mapping.timestamp],
379	            ['resource_cost_units', mapping.resource_cost_units],
380	            ['retry_attempt', mapping.retry_attempt],
381	            ['task_name', mapping.task_name],
382	        ];
383	        for (const [field, path] of optionals) {
384	            if (!path) continue;
385	            const val = deepGet(record, path);
386	            if (val !== undefined) mapped[field] = val;
387	        }
388	
389	        // Preserve the original record as raw_context for auditability
390	        mapped._original = record;
391	        mapped._inferred_by = 'schema-inferrer';
392	        mapped._detected_framework = mapping.detected_framework;
393	
394	        return mapped;
395	    });
396	}
