132	async function generateOpenAIEmbedding(text: string): Promise<number[] | null> {
133	    if (!OPENAI_API_KEY) {
134	        console.warn('[context-embed] OPENAI_API_KEY not set — using exact match fallback');
135	        return null;
136	    }
137	
138	    try {
139	        const response = await fetch('https://api.openai.com/v1/embeddings', {
140	            method: 'POST',
141	            headers: {
142	                'Authorization': `Bearer ${OPENAI_API_KEY}`,
143	                'Content-Type': 'application/json',
144	            },
145	            body: JSON.stringify({
146	                input: text,
147	                model: 'text-embedding-3-small',
148	                dimensions: EXPECTED_CONTEXT_VECTOR_DIMENSION,
149	            }),
150	        });
151	
152	        if (!response.ok) {
153	            console.warn(`[context-embed] OpenAI API error: ${response.status}`);
154	            return null;
155	        }
156	
157	        const json = await response.json() as any;
158	        return json?.data?.[0]?.embedding ?? null;
159	    } catch (err: any) {
160	        console.warn('[context-embed] OpenAI embedding error:', err.message);
161	        return null;
162	    }
163	}
