288	// FALLBACK: used when match_context_vector RPC is unavailable.
289	// Customer-scoped but O(n/customers) — acceptable for dev/small datasets.
290	// In production with pgvector RPC deployed, this path should not be hit.
291	async function findClosestContextFallback(
292	    embedding: number[],
293	    customerId: string,
294	    environment?: string
295	): Promise<{ context_id: string; similarity: number } | null> {
296	    let query = supabase
297	        .from('dim_contexts')
298	        .select('context_id, context_vector, embedding_model, source_text, embedding_schema_version')
299	        .eq('customer_id', customerId)
300	        .eq('embedding_schema_version', CURRENT_EMBEDDING_SCHEMA_VERSION)
301	        .not('context_vector', 'is', null);
302	
303	    if (environment) {
304	        query = query.eq('environment', environment);
305	    }
306	
307	    const { data, error } = await query;
308	
309	    if (error || !data || data.length === 0) {
310	        return null;
311	    }
312	
313	    let bestMatch: { context_id: string; similarity: number } | null = null;
314	
315	    for (const row of data) {
316	        if (row.context_vector === null || row.context_vector === undefined) continue;
317	
318	        // Skip vectors from incompatible embedding models to avoid meaningless scores.
319	        // Null embedding_model means legacy row (pre-migration 056) — allow through conservatively.
320	        if (row.embedding_model && row.embedding_model !== CURRENT_EMBEDDING_MODEL) {
321	            console.warn(
322	                `[context-embed] Skipping context ${row.context_id}: model mismatch ` +
323	                `(stored=${row.embedding_model}, current=${CURRENT_EMBEDDING_MODEL}). ` +
324	                'Run batch re-embedding to migrate.'
325	            );
326	            continue;
327	        }
328	
329	        const storedVec = typeof row.context_vector === 'string'
330	            ? parseVector(row.context_vector)
331	            : (row.context_vector as number[]);
332	
333	        if (!storedVec) {
334	            console.warn(`[context-embed] Skipping context ${row.context_id}: failed to parse stored vector string.`);
335	            continue;
336	        }
337	        if (storedVec.length === 0) continue;
338	
339	        // Dimension safety check before computing similarity
340	        if (storedVec.length !== embedding.length) {
341	            console.warn(
342	                `[context-embed] Skipping context ${row.context_id}: dimension mismatch ` +
343	                `(stored=${storedVec.length}, query=${embedding.length})`
344	            );
345	            continue;
346	        }
347	
348	        const sim = cosineSimilarity(embedding, storedVec);
349	
350	        if (sim > SIMILARITY_THRESHOLD && (!bestMatch || sim > bestMatch.similarity)) {
351	            bestMatch = { context_id: row.context_id, similarity: sim };
352	        }
353	    }
354	
355	    return bestMatch;
356	}
