404	/**
405	 * Build context text from components for embedding.
406	 */
407	export function buildContextText(
408	    issueType: string,
409	    customerTier?: string,
410	    environment?: string,
411	    rawContext?: Record<string, unknown>
412	): string {
413	    const rawContextText = flattenRawContextForEmbedding(rawContext);
414	    return [issueType, customerTier, environment, rawContextText]
415	        .filter(Boolean)
416	        .join(' ')
417	        .trim();
418	}
