420	/**
421	 * Ensures a context row has a vector + embedding metadata.
422	 * Safe to call on every ingestion path; fast-path exits when vector already exists.
423	 */
424	export async function ensureContextEmbedding(params: {
425	    contextId: string;
426	    customerId: string;
427	    issueType: string;
428	    customerTier?: string | null;
429	    environment?: string | null;
430	    rawContext?: Record<string, unknown> | null;
431	}): Promise<boolean> {
432	    const readyUntil = contextEmbeddingReadyUntil.get(params.contextId);
433	    if (readyUntil && readyUntil > Date.now()) {
434	        return true;
435	    }
436	
437	    const existingInFlight = contextEmbeddingInFlight.get(params.contextId);
438	    if (existingInFlight) {
439	        return existingInFlight;
440	    }
441	
442	    const task = (async () => {
443	        const { data: existing, error: existingError } = await supabase
444	            .from('dim_contexts')
445	            .select('context_vector, issue_type, customer_tier, environment')
446	            .eq('context_id', params.contextId)
447	            .eq('customer_id', params.customerId)
448	            .maybeSingle();
449	
450	        if (existingError || !existing) {
451	            if (existingError) {
452	                console.warn('[context-embed] ensureContextEmbedding lookup failed:', existingError.message);
453	            }
454	            return false;
455	        }
456	
457	        if ((existing as any).context_vector) {
458	            contextEmbeddingReadyUntil.set(
459	                params.contextId,
460	                Date.now() + CONTEXT_EMBEDDING_CACHE_TTL_MS,
461	            );
462	            return true;
463	        }
464	
465	        const sourceText = buildContextText(
466	            params.issueType || String((existing as any).issue_type ?? ''),
467	            params.customerTier ?? String((existing as any).customer_tier ?? ''),
468	            params.environment ?? String((existing as any).environment ?? ''),
469	            params.rawContext ?? undefined,
470	        );
471	
472	        if (!sourceText) {
473	            return false;
474	        }
475	
476	        const embedding = await generateEmbedding(sourceText);
477	        if (!embedding) {
478	            return false;
479	        }
480	
481	        const metadata = embeddingVersionMeta(embedding, sourceText);
482	        const { error: updateError } = await supabase
483	            .from('dim_contexts')
484	            .update({
485	                context_vector: embedding,
486	                ...metadata,
487	            })
488	            .eq('context_id', params.contextId)
489	            .eq('customer_id', params.customerId)
490	            .is('context_vector', null);
491	
492	        if (updateError) {
493	            console.warn('[context-embed] ensureContextEmbedding update failed:', updateError.message);
494	            return false;
495	        }
496	
497	        contextEmbeddingReadyUntil.set(
498	            params.contextId,
499	            Date.now() + CONTEXT_EMBEDDING_CACHE_TTL_MS,
500	        );
501	        return true;
502	    })();
503	
504	    contextEmbeddingInFlight.set(params.contextId, task);
505	
506	    try {
507	        return await task;
508	    } finally {
509	        contextEmbeddingInFlight.delete(params.contextId);
510	    }
511	}
