1	export type OutcomeQuality = 'high' | 'medium' | 'low';
2	
3	const DAY_MS = 24 * 60 * 60 * 1000;
4	
5	export const HIGH_QUALITY_WEIGHT = 1.0;
6	export const MEDIUM_QUALITY_WEIGHT = 0.6;
7	export const LOW_QUALITY_WEIGHT = 0.25;
8	
9	export const HIGH_QUALITY_HALF_LIFE_DAYS = 90;
10	export const MEDIUM_QUALITY_HALF_LIFE_DAYS = 45;
11	export const LOW_QUALITY_HALF_LIFE_DAYS = 14;
12	
13	export const LOW_QUALITY_HARD_EXCLUSION_DAYS = 30;
14	
15	function clamp01(value: number): number {
16	    if (!Number.isFinite(value)) return 0;
17	    return Math.max(0, Math.min(1, value));
18	}
19	
20	export function classifyOutcomeQuality(outcomeScore: number): OutcomeQuality {
21	    const score = clamp01(outcomeScore);
22	    if (score >= 0.8) return 'high';
23	    if (score >= 0.5) return 'medium';
24	    return 'low';
25	}
26	
27	function qualityWeight(quality: OutcomeQuality): number {
28	    switch (quality) {
29	        case 'high':
30	            return HIGH_QUALITY_WEIGHT;
31	        case 'medium':
32	            return MEDIUM_QUALITY_WEIGHT;
33	        case 'low':
34	        default:
35	            return LOW_QUALITY_WEIGHT;
36	    }
37	}
38	
39	function qualityHalfLifeDays(quality: OutcomeQuality): number {
40	    switch (quality) {
41	        case 'high':
42	            return HIGH_QUALITY_HALF_LIFE_DAYS;
43	        case 'medium':
44	            return MEDIUM_QUALITY_HALF_LIFE_DAYS;
45	        case 'low':
46	        default:
47	            return LOW_QUALITY_HALF_LIFE_DAYS;
48	    }
49	}
50	
51	export function getAgeDays(timestamp: string | null, nowMs = Date.now()): number | null {
52	    if (!timestamp) return null;
53	    const ts = Date.parse(timestamp);
54	    if (!Number.isFinite(ts)) return null;
55	    const ageDays = Math.max(0, (nowMs - ts) / DAY_MS);
56	    return Number(ageDays.toFixed(6));
57	}
58	
59	export function computeOutcomeEffectiveWeightForScore(
60	    outcomeScore: number,
61	    timestamp: string | null,
62	    nowMs = Date.now(),
63	): number {
64	    const quality = classifyOutcomeQuality(outcomeScore);
65	    const ageDays = getAgeDays(timestamp, nowMs);
66	
67	    if (quality === 'low' && ageDays !== null && ageDays > LOW_QUALITY_HARD_EXCLUSION_DAYS) {
68	        return 0;
69	    }
70	
71	    const baseWeight = qualityWeight(quality);
72	    if (ageDays === null) {
73	        return baseWeight;
74	    }
75	
76	    const halfLifeDays = qualityHalfLifeDays(quality);
77	    const decay = Math.exp(-Math.LN2 * ageDays / halfLifeDays);
78	    const effectiveWeight = baseWeight * decay;
79	
80	    return Number(effectiveWeight.toFixed(6));
81	}
